var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠…… 맥크레디 영지인가. 오늘은 유달리 안개가 짙군.","JPN":"ふむ……マクレディー領地か。今日はひときわ霧が濃いな。","ENG":"Hmm... MacCready Estate's fog is unusually thick today.","TWN":"嗯……麥克蕾蒂領地嗎，今天霧特別大。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"언제 와도 그리운 장소야……","JPN":"いつ来ても懐かしい場所だ……","ENG":"This place brings back memories...","TWN":"不管什麼時候來都很懷念啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오셨군요, 생물학부장. 학회장 대행이 보내던가요.","JPN":"来ましたね、生物学部長。学会長代行が向かわせたのですか。","ENG":"You've arrived, Dean of Biology. Did the Acting President send you?","TWN":"你來了，生物學院院長。是代理學會長送你來的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오. 법학부장. 한 발 먼저 와 있었구려.","JPN":"ほう。法学部長。先に来ていたのか。","ENG":"Ho-oh, isn't this the Dean of Law. You're a step ahead.","TWN":"噢噢，法學院院長。你先我一步到這裡了啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 학회장의 예상이 들어맞은 건가……. 과연 혜안이라고 해야 할지.","JPN":"なら学会長の予想どおりということか……さすが、慧眼というべきか。","ENG":"Then does this mean that the President's predictions were correct...? Or should I call it her wisdom?","TWN":"那學會長猜對了嗎……果然她是獨具慧眼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"융합체들을 데려왔소. 부학회장 체포에 도움이 될 거요.","JPN":"融合体を連れてきた。副学会長を捕らえるのに役立つだろう。","ENG":"I brought the hybriders. They will be of assistance in capturing the Vice President.","TWN":"我帶來了融合體。對逮捕副學會長會有幫助的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장이라면 이미 저택으로 향했습니다.","JPN":"副学会長なら、すでに邸宅へ向かいました。","ENG":"The Vice President has already headed back to the mansion.","TWN":"副學會長，她已經去宅邸了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭐요?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지금 내가 잘못 들은 건가? 그걸 알고도 여기서 팔짱 끼고 있었소?","JPN":"私の聞き間違いか？　それを知っていながらここで手をこまねいていたのか？","ENG":"Did I hear that right? Then what are you doing here with your arms crossed?","TWN":"現在是我聽錯了嗎？你明知道這件事，卻只是旁觀嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회를 손에 넣으려면 학회장 대행부터 넘어야 할 텐데요.","JPN":"学会を手に入れるためには、学会長代行からどうにかしないといけないはずですが。","ENG":"If you want to take control of the Society, you will first have to overthrow the current Acting President.","TWN":"要想把學會拿到手，你必須先打敗代理學會長。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저에게도 쩔쩔 매는 주제에, 그런 일이 가당키나 할 거라고 생각합니까?","JPN":"私相手にも手こずっているくせに、そんなことができるとでも思っているのですか？","ENG":"But how are you going to do that when you can't even defeat me?","TWN":"你連我都贏不了，你覺得這事有可能嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"할 수 있어요.","JPN":"できますわ。","ENG":"I can do it.","TWN":"我可以。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니, 해내겠습니다. 람다 스파타리.","JPN":"いいえ、やってみせます。ラムダ・スパタリー。","ENG":"No. I must, Lamda Spatari.","TWN":"不，我一定會做到，蘭達·史派特。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힘을 빌려 달라고 하진 않겠어요.","JPN":"力を貸してくれとは言いません。","ENG":"I will not ask for your help.","TWN":"我不求你幫我。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"최소한, 마지막까지 지켜봐 주세요.","JPN":"少なくとも、最後まで見届けてください。","ENG":"But at the very least, please watch over me until the very end.","TWN":"但至少，請你看到最後。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다른 사람이어서는 안 됩니다. 당신이어야 해요.","JPN":"他の人では駄目です。絶対にあなたでないと。","ENG":"It cannot be anyone else. It has to be you.","TWN":"別人不行，必須是你。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사정 청취를 통해 양측의 입장에 차이가 있다는 사실을 확인했습니다.","JPN":"事情聴取により、両方の立場に相違があるということを確認しました。","ENG":"I conducted a preliminary hearing and confirmed that there is a discrepancy between the two sides.","TWN":"透過聽取事情的緣由，我確認了雙方立場上存在差異的事實。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};